"use client";
import React, { useEffect, useState } from "react";
import { useParams } from "next/navigation";
import { db } from "../../lib/firebase";
import { doc, getDoc } from "firebase/firestore";

const page = async ({ params }) => {
//   const { id } = await params;

  const [customer, setCustomer] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  useEffect(() => {
    const fetchCustomer = async () => {
      if (!id) return;

      try {
        // NOTE: Ensure your collection is named "customerName"
        // or is it "customers"? Double check Firebase Console.
        const docRef = doc(db, "customerName", id);
        const docSnap = await getDoc(docRef);

        if (docSnap.exists()) {
          setCustomer(docSnap.data());
        } else {
          setError("No customer found with this ID.");
        }
      } catch (err) {
        setError("Error: " + err.message);
      } finally {
        setLoading(false); // This stops the loading screen
      }
    };

    fetchCustomer();
  }, [id]);

  if (loading) return <p>Loading...</p>;
  if (error) return <p style={{ color: "red" }}>{error}</p>;

  return (
    <div>
      <h1>Customer Details</h1>
      {customer ? (
        <>
          <p>
            <strong>Name:</strong> {customer.customerName}
          </p>
          <p>
            <strong>ID:</strong> {id}
          </p>
        </>
      ) : (
        <p>No data available.</p>
      )}
    </div>
  );
};

export default page;
